import{_ as a,o,c as s,a0 as r}from"./chunks/framework.BjpW4enL.js";const u=JSON.parse('{"title":"ADR-0002: Operadores Relacionais Composáveis no T4 para Compilação Topológica de Esquemas","description":"","frontmatter":{},"headers":[],"relativePath":"20_Arquitetura/adr/0002-operadores-relacionais-componiveis-T4.md","filePath":"20_Arquitetura/adr/0002-operadores-relacionais-componiveis-T4.md","lastUpdated":1782592277000}'),t={name:"20_Arquitetura/adr/0002-operadores-relacionais-componiveis-T4.md"};function i(n,e,d,c,l,p){return o(),s("div",null,[...e[0]||(e[0]=[r(`<h1 id="adr-0002-operadores-relacionais-composaveis-no-t4-para-compilacao-topologica-de-esquemas" tabindex="-1">ADR-0002: Operadores Relacionais Composáveis no T4 para Compilação Topológica de Esquemas <a class="header-anchor" href="#adr-0002-operadores-relacionais-composaveis-no-t4-para-compilacao-topologica-de-esquemas" aria-label="Permalink to &quot;ADR-0002: Operadores Relacionais Composáveis no T4 para Compilação Topológica de Esquemas&quot;">​</a></h1><h2 id="status" tabindex="-1">Status <a class="header-anchor" href="#status" aria-label="Permalink to &quot;Status&quot;">​</a></h2><p>Implementado parcialmente — Operadores REST expostos via engine.</p><ul><li><code>nexus_find</code> → <strong>Não implementado</strong> (rota 404)</li><li><code>nexus_expand</code> → <strong>Não implementado</strong> (rota 404)</li><li><code>nexus_project</code> → <code>POST /t4/project</code> (projeção do grafo multi-relacional) ✅</li><li><code>nexus_abstract</code> → <code>POST /t4/abstract</code> (fingerprinting Weisfeiler-Lehman) ✅</li><li><code>nexus_compile</code> → <code>POST /t4/compile</code> (compilação de fingerprints em schemas) ✅</li><li><code>nexus_chain</code> → <code>POST /t4/chain</code> (pipeline runtime, campo esperado: <code>steps</code> não <code>operations</code>) ✅</li></ul><p><strong>Nota:</strong> <code>find</code> e <code>expand</code> nunca foram implementados como endpoints. A navegação é feita via <code>project</code> (subgrafo por critério) + <code>expand</code> não existe — usa-se <code>project</code> com diferentes parâmetros.</p><h2 id="contexto" tabindex="-1">Contexto <a class="header-anchor" href="#contexto" aria-label="Permalink to &quot;Contexto&quot;">​</a></h2><p>O NEXUS opera com dois sistemas de referência cruzada:</p><ol><li><strong>T3 (Qdrant/Espaço Vetorial):</strong> Busca semântica aproximada por similaridade de cosseno. Responde &quot;o que parece com isto?&quot; — útil para descoberta, mas sem garantia de correção estrutural.</li><li><strong>T4 (Grafo Multi-Relacional/PostgreSQL):</strong> Arestas exatas e aproximadas entre nós de abstração (<code>part_of</code>, <code>depends_on:imports</code>, <code>semantic_bridge</code>, <code>contradicts</code>). Três camadas de rigidez: esqueleto (fatos estruturais), carne (aproximações semânticas), cartilagem (classificação por eixos <code>criteria × file_type × project</code>).</li></ol><p>O pipeline atual de enriquecimento (L0→L1→L2→Qdrant upsert + weaver) extrai relações estruturais no nível de <strong>chunks de código</strong> — funções, classes, imports. O T4 hoje navega entre file nodes e chunks, mas as entidades do grafo são fragmentos de arquivos, não <strong>estruturas relacionais completas</strong>.</p><p>Paralelamente, a ferramenta <strong>Codanna</strong> demonstrou um padrão eficaz de operadores relacionais composáveis:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>find_symbol(&quot;Parser&quot;)</span></span>
<span class="line"><span>  → get_calls(parser)       # o que Parser chama</span></span>
<span class="line"><span>  → find_callers(parser)    # quem chama Parser</span></span>
<span class="line"><span>  → analyze_impact(parser)  # grafo completo de dependências</span></span>
<span class="line"><span>  → chain(symbol_id)        # profundidade via composição</span></span></code></pre></div><p>Cada operador é uma transformação pura: recebe um conjunto de entradas (símbolos), retorna um conjunto de saídas (relacionados). A composição de operadores forma uma <strong>lei</strong> (query) que pode ser reaplicada em diferentes contextos. A chave do Codanna não é o que cada operador faz individualmente — é que os operadores são <strong>composáveis</strong>, <strong>tipados</strong> (cada operador tem entrada/saída bem definida), e <strong>encadeáveis</strong> (o output de um alimenta o input do próximo via <code>symbol_id</code>).</p><p>O desafio que se coloca agora é: <strong>como elevar este padrão de operadores composáveis ao nível topológico (T4), onde as entidades não são mais símbolos de código, mas estruturas relacionais inteiras?</strong></p><h3 id="o-problema-central" tabindex="-1">O Problema Central <a class="header-anchor" href="#o-problema-central" aria-label="Permalink to &quot;O Problema Central&quot;">​</a></h3><p>Em bases de código tradicionais, as relações são explícitas: imports, chamadas de função, herança de classe. Em datasets massivos de alto valor (múltiplos schemas SQL, bases documentais heterogêneas, corpora multi-lingua), as <strong>entidades e relações não são dadas a priori</strong> — elas precisam ser descobertas, abstraídas e formalizadas.</p><ul><li>Um schema SQL de 200 tabelas com milhares de colunas, FKs, índices, views materializadas, triggers, RLS policies — a &quot;entidade&quot; relevante pode ser um agregado de 12 tabelas interligadas por FKs e regras de negócio, não uma tabela individual.</li><li>Um dataset de documentos jurídicos com citações cruzadas, hierarquias normativas, revogações tácitas — a &quot;relação&quot; relevante pode ser uma cadeia de precedência que cruza 30 documentos, não uma referência direta.</li><li>Um corpus de telemetria de microserviços com 500 endpoints, 2000 chamadas RPC, latências e dependências não-lineares — a &quot;estrutura&quot; relevante pode ser um subgrafo de serviços que compartilham estado, não um grafo de chamadas plano.</li></ul><p>Precisamos de operadores que trabalhem <strong>no nível topológico</strong> — que recebam uma estrutura relacional inteira como entrada e produzam uma nova estrutura relacional como saída — com garantias consistentes de endereçamento e composição.</p><h2 id="decision-drivers" tabindex="-1">Decision Drivers <a class="header-anchor" href="#decision-drivers" aria-label="Permalink to &quot;Decision Drivers&quot;">​</a></h2><ul><li><strong>Composabilidade:</strong> Operadores devem ser encadeáveis como funções puras — a saída de um operador deve poder alimentar o próximo sem adaptação manual.</li><li><strong>Consistência de Endereçamento:</strong> Cada entidade no T4 precisa de um identificador estável e imutável (UUID) que persista através de transformações — análogo ao <code>symbol_id</code> do Codanna, mas para estruturas relacionais inteiras.</li><li><strong>Invariância de Nível:</strong> Operadores devem preservar ou explicitar o nível de abstração. Um operador que cruza tabelas de um schema SQL opera no nível <code>schema</code>; um que cruza schemas entre bancos opera no nível <code>federation</code>. A composição entre níveis diferentes deve ser mediada por operadores de projeção/reificação explícitos.</li><li><strong>Independência de Domínio:</strong> Os operadores devem funcionar para schemas SQL, documentos jurídicos, grafos de telemetria — qualquer domínio onde existam entidades relacionais identificáveis.</li><li><strong>Tratamento de Incerteza:</strong> Diferente do <code>depends_on:imports</code> (fato estrutural), operadores de descoberta operam com thresholds de similaridade. O sistema deve expor a confiança de cada aresta produzida, permitindo que o agente decida se confia ou não.</li></ul><h2 id="considered-options" tabindex="-1">Considered Options <a class="header-anchor" href="#considered-options" aria-label="Permalink to &quot;Considered Options&quot;">​</a></h2><h3 id="opcao-1-operadores-especificos-por-dominio-status-quo-estendido" tabindex="-1">Opção 1: Operadores Específicos por Domínio (Status Quo Estendido) <a class="header-anchor" href="#opcao-1-operadores-especificos-por-dominio-status-quo-estendido" aria-label="Permalink to &quot;Opção 1: Operadores Específicos por Domínio (Status Quo Estendido)&quot;">​</a></h3><p>Criar operadores especializados para cada tipo de dado: <code>get_tables(schema)</code>, <code>get_foreign_keys(table)</code>, <code>get_callers(endpoint)</code>. Cada operador com semântica própria, sem interface unificada.</p><ul><li><strong>Pros:</strong> Simples de implementar para cada domínio isoladamente. Baixo custo inicial.</li><li><strong>Cons:</strong> Não composável. Cada dupla de operadores precisa de adaptação manual. A &quot;lei&quot; (query composta) não é reutilizável entre domínios. Não resolve o problema de abstração topológica — apenas empurra a complexidade para o agente.</li></ul><h3 id="opcao-2-operadores-genericos-com-projecao-por-eixos-extensao-do-t4-atual" tabindex="-1">Opção 2: Operadores Genéricos com Projeção por Eixos (Extensão do T4 Atual) <a class="header-anchor" href="#opcao-2-operadores-genericos-com-projecao-por-eixos-extensao-do-t4-atual" aria-label="Permalink to &quot;Opção 2: Operadores Genéricos com Projeção por Eixos (Extensão do T4 Atual)&quot;">​</a></h3><p>Generalizar o padrão atual do T4 — onde <code>criteria × file_type × project</code> define fatias do grafo — para criar operadores genéricos que operam sobre qualquer combinação de eixos:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>find_entities(criteria=part_of, project=intraclinica-ng, file_type=sql)</span></span>
<span class="line"><span>  → traverse(target=&quot;outbound&quot;, criteria=&quot;depends_on:imports&quot;)</span></span>
<span class="line"><span>  → project(axis=&quot;file_type&quot;, value=&quot;typescript&quot;)</span></span>
<span class="line"><span>  → impact_analysis(depth=3)</span></span></code></pre></div><ul><li><strong>Pros:</strong> Reutiliza a estrutura de eixos já existente no T4. Operadores independentes de domínio. Composição natural (saída = conjunto de nós no grafo, que alimenta o próximo operador).</li><li><strong>Cons:</strong> O modelo atual do T4 opera no nível de file nodes e chunks, não no nível de <em>estruturas relacionais completas</em>. Um conjunto de tabelas SQL que formam um agregado de domínio não é um nó — são múltiplos nós conectados por arestas. Operadores genéricos precisariam de <strong>clusterização</strong> para tratar múltiplos nós como uma entidade única.</li></ul><h3 id="opcao-3-operadores-topologicos-com-entidades-como-subgrafos-proposta" tabindex="-1">Opção 3: Operadores Topológicos com Entidades como Subgrafos (Proposta) <a class="header-anchor" href="#opcao-3-operadores-topologicos-com-entidades-como-subgrafos-proposta" aria-label="Permalink to &quot;Opção 3: Operadores Topológicos com Entidades como Subgrafos (Proposta)&quot;">​</a></h3><p>Elevar o nível de abstração: em vez de operar sobre nós individuais, os operadores operam sobre <strong>subgrafos rotulados</strong> — conjuntos de nós + arestas que formam uma estrutura relacional coerente.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># Operadores fundamentais no nível topológico</span></span>
<span class="line"><span></span></span>
<span class="line"><span>find_entity(subgraph_schema)        → entidade: subgrafos que casam o schema</span></span>
<span class="line"><span>  → expand(entity, criteria_set)    # expande o subgrafo por tipos de aresta</span></span>
<span class="line"><span>  → project(entity, axes)           # projeta em sub-eixos (fatia)</span></span>
<span class="line"><span>  → abstract(entities)              # generaliza: encontra forma canônica entre subgrafos</span></span>
<span class="line"><span>  → compile(abstract_form, target)  # materializa: gera schema concreto alvo</span></span>
<span class="line"><span>  → chain(id)                       # conecta saída de um operador na entrada do próximo</span></span></code></pre></div><p>Onde cada entidade topológica é definida por:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Entity {</span></span>
<span class="line"><span>  id: UUID,               // estável, imutável — o symbol_id do T4</span></span>
<span class="line"><span>  nodes: Set&lt;NodeID&gt;,     // nós do grafo T4 que compõem a entidade</span></span>
<span class="line"><span>  edges: Set&lt;Edge&gt;,       // arestas internas (conectividade do subgrafo)</span></span>
<span class="line"><span>  boundary: Set&lt;Edge&gt;,    // arestas de fronteira (conexões com o exterior)</span></span>
<span class="line"><span>  schema: TypeSchema,     // forma abstrata que a entidade implementa</span></span>
<span class="line"><span>  confidence: f64         // grau de certeza (1.0 = fato, 0.0 = hipótese)</span></span>
<span class="line"><span>}</span></span></code></pre></div><p><strong>Pros:</strong></p><ul><li>Composabilidade real: operadores são transformações <code>Entity → Entity</code></li><li>Endereçamento consistente: UUID estável persiste através da cadeia</li><li>Independência de domínio: tabelas SQL, documentos jurídicos, microserviços — tudo são subgrafos</li><li>A lei (composição de operadores) pode ser serializada, versionada, reaplicada</li><li>A operação <code>compile(abstract_form, target)</code> permite gerar schemas concretos a partir de formas abstratas descobertas em datasets massivos</li></ul><p><strong>Cons:</strong></p><ul><li>Maior complexidade de implementação: requer detecção de subgrafos, operações de junção/projeção em grafos</li><li>Clusterização de nós em entidades requer algoritmo de community detection ou seed-based expansion</li><li>A noção de &quot;schema&quot; de uma entidade topológica precisa ser formalizada (TypeSchema)</li></ul><h3 id="opcao-4-operadores-hibridos-t3-t4-exploracao-vetorial-expansao-topologica" tabindex="-1">Opção 4: Operadores Híbridos T3+T4 (Exploração Vetorial + Expansão Topológica) <a class="header-anchor" href="#opcao-4-operadores-hibridos-t3-t4-exploracao-vetorial-expansao-topologica" aria-label="Permalink to &quot;Opção 4: Operadores Híbridos T3+T4 (Exploração Vetorial + Expansão Topológica)&quot;">​</a></h3><p>Em vez de operar puramente no grafo T4, usar T3 para encontrar sementes semanticamente similares e T4 para expandir estruturalmente — o triângulo canônico T3→T4→L3, formalizado como operadores composáveis.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>semantic_seed(query, top_k=5)        # T3: busca vetorial → N sementes</span></span>
<span class="line"><span>  → structural_expand(seed, depth=3) # T4: caminha grafo a partir de cada semente</span></span>
<span class="line"><span>  → cluster(subgraphs)               # L3: detecta comunidades → entidades emergentes</span></span>
<span class="line"><span>  → abstract(entities)               # generaliza entidades → forma canônica</span></span>
<span class="line"><span>  → compile(form, engine=&quot;sql&quot;)      # materializa forma em schema SQL</span></span></code></pre></div><ul><li><strong>Pros:</strong> Aproveita o melhor dos dois sistemas — busca semântica para descoberta (T3) + expansão exata para estrutura (T4). O L3 emerge naturalmente como community detection.</li><li><strong>Cons:</strong> Herda a incerteza do T3 (threshold de similaridade) que contamina a cadeia. A composição entre operadores T3 e T4 requer conversão explícita de coordenadas (espaço vetorial ↔ grafo).</li></ul><h2 id="decisao" tabindex="-1">Decisão <a class="header-anchor" href="#decisao" aria-label="Permalink to &quot;Decisão&quot;">​</a></h2><p>Adotaremos a <strong>Opção 3 (Operadores Topológicos com Entidades como Subgrafos)</strong> como direção arquitetural, com os seguintes operadores fundamentais:</p><h3 id="operadores-canonicos" tabindex="-1">Operadores Canônicos <a class="header-anchor" href="#operadores-canonicos" aria-label="Permalink to &quot;Operadores Canônicos&quot;">​</a></h3><p>Seja ε o conjunto de todas as entidades topológicas (subgrafos rotulados) no T4:</p><table tabindex="0"><thead><tr><th>Operador</th><th>Assinatura</th><th>Descrição</th></tr></thead><tbody><tr><td><code>find(subgraph_schema)</code></td><td>Schema → P(ε)</td><td>Encontra subgrafos no T4 que casam um schema de entidade</td></tr><tr><td><code>expand(entity, criteria_set)</code></td><td>ε × P(C) → ε</td><td>Expande a fronteira do subgrafo por tipos de aresta</td></tr><tr><td><code>project(entity, axes)</code></td><td>ε × P(A) → ε</td><td>Fatia o subgrafo por eixos de projeção</td></tr><tr><td><code>abstract(entities)</code></td><td>P(ε) → F</td><td>Generaliza múltiplas entidades em uma forma canônica</td></tr><tr><td><code>compile(form, engine)</code></td><td>F × Engine → Schema</td><td>Materializa uma forma canônica em schema concreto</td></tr><tr><td><code>chain(entity, operator)</code></td><td>ε × O → ε</td><td>Conecta saída de um operador na entrada do próximo</td></tr></tbody></table><h3 id="relacao-com-os-eixos-t4-existentes" tabindex="-1">Relação com os Eixos T4 Existentes <a class="header-anchor" href="#relacao-com-os-eixos-t4-existentes" aria-label="Permalink to &quot;Relação com os Eixos T4 Existentes&quot;">​</a></h3><p>Os operadores não substituem os eixos atuais do T4 (<code>criteria × file_type × project</code>) — eles os <strong>encapsulam</strong>. O operador <code>project(entity, axes)</code> é uma generalização do conceito de fatia: em vez de projetar sobre file nodes, projeta sobre qualquer entidade topológica, usando os mesmos eixos como filtros.</p><p>O operador <code>expand(entity, criteria_set)</code> corresponde a caminhar o grafo T4 por tipos específicos de aresta — exatamente como <code>nexus_adjacent(file_node)</code> funciona hoje, mas com a diferença fundamental de que a expansão pode parar na <strong>fronteira</strong> da entidade, distinguindo arestas internas (conectividade do subgrafo) de arestas de fronteira (conexões com o exterior).</p><h3 id="a-operacao-abstract-o-coracao-da-compilacao-topologica" tabindex="-1">A Operação <code>abstract</code>: O Coração da Compilação Topológica <a class="header-anchor" href="#a-operacao-abstract-o-coracao-da-compilacao-topologica" aria-label="Permalink to &quot;A Operação \`abstract\`: O Coração da Compilação Topológica&quot;">​</a></h3><p>A operação <code>abstract(entities)</code> recebe um conjunto de entidades (subgrafos) e produz uma <strong>Forma Canônica</strong> — uma generalização que captura o padrão invariante entre elas. Este é o mecanismo que permite:</p><ol><li><p><strong>Descobrir formas abstratas em datasets massivos:</strong> Dado um dataset de 500 schemas SQL de diferentes sistemas, <code>abstract(schemas)</code> produz uma forma canônica que captura o padrão relacional comum — &quot;todo sistema de agendamento tem uma tabela <code>appointments</code> com FKs para <code>patients</code> e <code>providers</code>, um status state machine, e um índice temporal para evitar conflitos de horário.&quot;</p></li><li><p><strong>Compilar formas abstratas em schemas concretos:</strong> Dado a forma canônica do parágrafo anterior, <code>compile(form, engine=&quot;postgresql&quot;)</code> gera um schema SQL inicial com as tabelas, colunas, FKs, índices e constraints que implementam o padrão — que pode então ser refinado manualmente.</p></li><li><p><strong>Generalizar entre domínios:</strong> Uma forma canônica descoberta em schemas SQL pode ser comparada com formas descobertas em schemas MongoDB (collections, embedded documents, indexes) — revelando isomorfismos estruturais entre paradigmas de banco diferentes.</p></li></ol><p>O algoritmo de <code>abstract</code> proposto:</p><ol><li>Alinhar os subgrafos por isomorfismo aproximado (kernel de Weisfeiler-Lehman)</li><li>Identificar nós e arestas consistentes entre todos os subgrafos (invariantes)</li><li>Parametrizar nós/arestas variantes (ex: nomes de tabela específicos → slots nomeados)</li><li>Produzir a forma canônica como um grafo com nós parametrizados e arestas invariantes</li></ol><h3 id="enderecamento-e-composicao-a-lei-como-query" tabindex="-1">Endereçamento e Composição: A &quot;Lei&quot; como Query <a class="header-anchor" href="#enderecamento-e-composicao-a-lei-como-query" aria-label="Permalink to &quot;Endereçamento e Composição: A &quot;Lei&quot; como Query&quot;">​</a></h3><p>Inspirado pelo <code>symbol_id</code> do Codanna, cada entidade topológica carrega um UUID estável. A composição de operadores forma uma <strong>lei</strong> — uma query topológica serializável:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// Exemplo: &quot;Encontre schemas de agendamento que usam PostgreSQL</span></span>
<span class="line"><span>//          e compile um schema inicial para TimescaleDB&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>find(schema=&quot;appointment_system_v1&quot;)</span></span>
<span class="line"><span>  → expand(criteria=[&quot;depends_on:imports&quot;, &quot;semantic_bridge&quot;])</span></span>
<span class="line"><span>  → project(axes={file_type: &quot;sql&quot;})</span></span>
<span class="line"><span>  → abstract()</span></span>
<span class="line"><span>  → compile(engine=&quot;timescaledb&quot;)</span></span></code></pre></div><p>Esta lei pode ser versionada, compartilhada entre agentes, e reaplicada em datasets diferentes. A diferença fundamental para uma query SQL tradicional é que a lei opera sobre <strong>topologia relacional</strong>, não sobre tuplas.</p><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><h3 id="por-que-a-opcao-3-e-nao-a-1-ou-2" tabindex="-1">Por que a Opção 3 e não a 1 ou 2? <a class="header-anchor" href="#por-que-a-opcao-3-e-nao-a-1-ou-2" aria-label="Permalink to &quot;Por que a Opção 3 e não a 1 ou 2?&quot;">​</a></h3><ul><li><p><strong>Opção 1</strong> (operadores específicos por domínio) falha na composabilidade — exatamente o problema que o Codanna resolveu com <code>symbol_id</code> universal. Se cada operador tem sua própria semântica de entrada/saída, não há &quot;lei&quot; reutilizável.</p></li><li><p><strong>Opção 2</strong> (operadores genéricos com projeção por eixos) é um passo intermediário correto, mas insuficiente. O T4 atual opera sobre nós individuais (file nodes, chunks), não sobre estruturas relacionais completas. A noção de &quot;entidade como subgrafo&quot; é a diferença entre ter um operador <code>find_tables(schema)</code> que retorna tabelas individuais e ter <code>find_aggregate(schema)</code> que retorna o subgrafo completo de tabelas interligadas que formam um agregado de domínio.</p></li></ul><h3 id="por-que-nao-a-opcao-4" tabindex="-1">Por que não a Opção 4? <a class="header-anchor" href="#por-que-nao-a-opcao-4" aria-label="Permalink to &quot;Por que não a Opção 4?&quot;">​</a></h3><p>A Opção 4 (híbrido T3+T4) é uma <strong>extensão futura</strong> válida, mas introduz dependência de similaridade vetorial no pipeline de compilação. A incerteza do T3 contamina a cadeia de operadores, exigindo propagação de confiança. A Opção 3 é mais pura: opera exclusivamente no grafo topológico, onde as arestas são fatos (esqueleto) ou aproximações explícitas (carne). O T3 entra como <strong>seed</strong> opcional na ponta do <code>find</code>, não como parte da cadeia de operadores.</p><h3 id="por-que-uuid-como-identificador-universal" tabindex="-1">Por que UUID como identificador universal? <a class="header-anchor" href="#por-que-uuid-como-identificador-universal" aria-label="Permalink to &quot;Por que UUID como identificador universal?&quot;">​</a></h3><p>O Codanna usa <code>symbol_id</code> numérico. No T4, UUID é necessário porque:</p><ol><li>Entidades topológicas podem ser compostas por múltiplos nós — UUID desacopla identidade de localização</li><li>UUID permite fusão: se dois subgrafos são reconhecidos como a mesma entidade em momentos diferentes, o UUID permanece estável</li><li>UUID é imutável através de transformações — <code>expand(entity)</code> preserva o UUID da entidade original</li></ol><h2 id="consequencias" tabindex="-1">Consequências <a class="header-anchor" href="#consequencias" aria-label="Permalink to &quot;Consequências&quot;">​</a></h2><h3 id="positivas" tabindex="-1">Positivas <a class="header-anchor" href="#positivas" aria-label="Permalink to &quot;Positivas&quot;">​</a></h3><ul><li><strong>Composabilidade real:</strong> Operadores <code>Entity → Entity</code> podem ser encadeados arbitrariamente. A &quot;lei&quot; (composição) é serializável como JSON e reaplicável.</li><li><strong>Independência de domínio:</strong> O mesmo conjunto de operadores funciona para schemas SQL, documentos jurídicos, grafos de telemetria. A diferença está no conteúdo do subgrafo, não na forma do operador.</li><li><strong>Descoberta em datasets massivos:</strong> <code>abstract(entities)</code> permite extrair formas canônicas de datasets de milhares de schemas — um mecanismo de engenharia reversa de bancos de dados em escala.</li><li><strong>Compilação de schemas:</strong> <code>compile(form, engine)</code> gera schemas concretos a partir de formas abstratas, acelerando a criação de novos bancos a partir de padrões descobertos na natureza.</li><li><strong>Integração natural com o T4 existente:</strong> Operadores reutilizam os eixos <code>criteria × file_type × project</code> como filtros de projeção. A tabela <code>agent_links</code> (93.957 arestas) já contém a matéria-prima para <code>expand</code> e <code>find</code>.</li></ul><h3 id="negativas" tabindex="-1">Negativas <a class="header-anchor" href="#negativas" aria-label="Permalink to &quot;Negativas&quot;">​</a></h3><ul><li><strong>Complexidade de <code>abstract</code>:</strong> O algoritmo de generalização de subgrafos (kernel de Weisfeiler-Lehman) é computacionalmente caro em datasets grandes. Exige implementação cuidadosa em Rust.</li><li><strong>Definição de TypeSchema:</strong> A noção de &quot;schema de entidade topológica&quot; precisa ser formalizada antes da implementação. Uma entidade SQL é diferente de uma entidade documental — o TypeSchema precisa ser um tipo algébrico que capture ambas.</li><li><strong>Consumer da lei:</strong> A &quot;lei&quot; (composição de operadores) precisa de um runtime de execução — um interpretador de pipelines topológicos. Isso é um componente novo na arquitetura.</li></ul><h3 id="riscos" tabindex="-1">Riscos <a class="header-anchor" href="#riscos" aria-label="Permalink to &quot;Riscos&quot;">​</a></h3><ul><li><strong>Super-engenharia antecipada:</strong> O formalismo de operadores pode ser excessivo se o número de domínios for pequeno. Deve ser validado com pelo menos 3 domínios distintos antes de generalizar.</li><li><strong>Performance de <code>abstract</code>:</strong> Weisfeiler-Lehman em subgrafos grandes pode ser O(n²) no pior caso. Mitigação: usar amostragem (top-k subgrafos por seed) e paralelização.</li><li><strong>Acoplamento T4:</strong> A implementação depende da maturidade do T4. Se o T4 ainda está em transição (ex: <code>semantic_bridge</code> sendo substituído), os operadores precisam ser resilientes a mudanças de schema de arestas.</li></ul><h2 id="implementation-notes" tabindex="-1">Implementation Notes <a class="header-anchor" href="#implementation-notes" aria-label="Permalink to &quot;Implementation Notes&quot;">​</a></h2><ol><li><p><strong>Fase 1 — Operadores de Navegação (<code>find</code>, <code>expand</code>, <code>project</code>):</strong> Implementar primeiro os operadores que são generalizações diretas do T4 existente. Reutilizar <code>nexus_adjacent</code> como backend. Adicionar o conceito de entidade como coleção de nós (subgrafo). Protótipo em Python puro para validação.</p></li><li><p><strong>Fase 2 — Operador <code>abstract</code>:</strong> Implementar kernel de Weisfeiler-Lehman para alinhamento de subgrafos. Protótipo em Python com NetworkX. Validar com 3 datasets: schemas SQL de intraclinica-ng, schemas NEXUS, schemas públicos de código aberto.</p></li><li><p><strong>Fase 3 — Operador <code>compile</code>:</strong> Mapear formas canônicas → DDL SQL (PostgreSQL, TimescaleDB). Seguir o padrão já estabelecido em intraclinica-ng (migrations numeradas, <code>CREATE TABLE ...</code>, FKs, índices, RLS). A saída deve ser um migration SQL válido.</p></li><li><p><strong>Fase 4 — Chain runtime:</strong> Implementar o interpretador de pipelines topológicos em Rust, exposto como MCP tools (<code>nexus_compose</code>, <code>nexus_discover</code>, <code>nexus_compile</code>).</p></li></ol><h2 id="related-decisions" tabindex="-1">Related Decisions <a class="header-anchor" href="#related-decisions" aria-label="Permalink to &quot;Related Decisions&quot;">​</a></h2><ul><li><strong>ADR-0001</strong> — Propagação de Carga e Retropropagação Dinâmica no Grafo T4 (os operadores de navegação podem alimentar o feedback de retropropagação com dados de navegação real)</li><li><strong>ADR-0017</strong> (Arquivado) — L2 Structure Inheritance from L1 (a compilação de schemas pode se beneficiar do merge L1+L2 para enriquecer formas canônicas com estrutura AST)</li><li><strong>ADR-0015</strong> (Arquivado) — Agent Stigmergy Triangulation (a stigmergia dos agentes pode ser usada como entrada para o operador <code>abstract</code> — rotas navegadas com frequência indicam relevância)</li><li><strong>ADR-0020</strong> (Arquivado) — Trajectory Subgraph Retrieval (a recuperação de subgrafos por trajetória é um caso particular do operador <code>find</code>)</li></ul><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li><strong>Codanna Documentation:</strong> <code>get_calls</code>, <code>find_callers</code>, <code>find_symbol</code>, <code>analyze_impact</code>, chaining via <code>symbol_id</code></li><li><strong>T4_GRAPH_NORMS.md:</strong> Especificação detalhada dos tipos de aresta do T4 e eixos de projeção</li><li><strong>CANONICAL_T4.md:</strong> Definição canônica do T4 como grafo multi-relacional</li><li><strong>Kernel de Weisfeiler-Lehman:</strong> Shervashidze et al., &quot;Weisfeiler-Lehman Graph Kernels&quot; (JMLR 2011)</li><li><strong>Tabela <code>agent_links</code>:</strong> 93.957 arestas no T4 (65.197 part_of, 22.232 successor, 5.491 semantic_bridge, 789 depends_on:imports, 248 contradicts), base para expansão topológica</li></ul><h2 id="apendice-a-—-mapeamento-para-redes-neurais-construtivas" tabindex="-1">Apêndice A — Mapeamento para Redes Neurais Construtivas <a class="header-anchor" href="#apendice-a-—-mapeamento-para-redes-neurais-construtivas" aria-label="Permalink to &quot;Apêndice A — Mapeamento para Redes Neurais Construtivas&quot;">​</a></h2><p>Este ADR foi inspirado por dois artigos de referência sobre o paradigma construtivo em redes neurais, disponíveis em <code>docs/reference/sintese-redes-neurais-construtivas.md</code>.</p><h3 id="a-1-operadores-t4-×-algoritmos-construtivos" tabindex="-1">A.1 Operadores T4 × Algoritmos Construtivos <a class="header-anchor" href="#a-1-operadores-t4-×-algoritmos-construtivos" aria-label="Permalink to &quot;A.1 Operadores T4 × Algoritmos Construtivos&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Operador T4 (ADR-0002)</th><th>Estratégia</th><th>Algoritmo Construtivo Análogo</th><th>Mecanismo</th></tr></thead><tbody><tr><td><code>expand(entity, criteria_set)</code></td><td>Expande fronteira do subgrafo</td><td><strong>Cascade Correlation</strong> (Fahlman &amp; Lebiere, 1990)</td><td>Adiciona neurônio oculto, congela pesos anteriores, treina nova unidade contra erro residual</td></tr><tr><td><code>find_entity(subgraph_schema)</code></td><td>Busca topológica guiada por schema</td><td><strong>A* Heuristic Search</strong> (Castro et al., 1999)</td><td>Busca heurística no espaço de arquiteturas; função de custo guia a expansão</td></tr><tr><td><code>project(entity, axes)</code></td><td>Fatia subgrafo por eixos, revela estrutura latente</td><td><strong>Projection Pursuit Learning (PPL)</strong> (Friedman &amp; Stuetzle, 1981)</td><td>Projeta dados em subespaço otimizado via polinômios de Hermite</td></tr><tr><td><code>abstract(entities)</code></td><td>Generaliza múltiplas entidades em forma canônica</td><td>— (não há análogo direto em redes construtivas)</td><td>Alinhamento por isomorfismo aproximado (Weisfeiler-Lehman)</td></tr><tr><td><code>compile(form, engine)</code></td><td>Materializa forma canônica em schema concreto</td><td>— (não há análogo direto)</td><td>Geração de DDL a partir de grafo abstrato</td></tr><tr><td>Fractal Boundary</td><td>Rejeita arestas/nós inconsistentes</td><td><strong>Pruning (poda)</strong> (Reed, 1993)</td><td>Elimina elementos que não contribuem para o resultado</td></tr></tbody></table><h3 id="a-2-ciclo-de-cristalizacao-t4-×-ciclo-construtivo" tabindex="-1">A.2 Ciclo de Cristalização T4 × Ciclo Construtivo <a class="header-anchor" href="#a-2-ciclo-de-cristalizacao-t4-×-ciclo-construtivo" aria-label="Permalink to &quot;A.2 Ciclo de Cristalização T4 × Ciclo Construtivo&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Fase T4</th><th>Fase Construtiva</th><th>Descrição</th></tr></thead><tbody><tr><td><strong>Fluida</strong></td><td>Topologia mínima inicial</td><td>Grafo mínimo, hipóteses fracas (equivalente à rede sem neurônios ocultos)</td></tr><tr><td><strong>Proving</strong></td><td>Erro residual → adiciona unidade</td><td>Operador <code>expand</code> adiciona nós/arestas quando a evidência atual é insuficiente</td></tr><tr><td><strong>Proving</strong> (refino)</td><td>Treinamento e ajuste fino</td><td>Refinamento de pesos (confiança) nas arestas existentes</td></tr><tr><td><strong>Cristalizada</strong></td><td>Erro abaixo do limiar → para</td><td>Arquitetura parcimoniosa; critério de parada análogo ao MSE ≤ 0.01</td></tr><tr><td>Contração</td><td>Poda de elementos redundantes</td><td>Eliminação de arestas/nós que não passam pelo crivo de consistência</td></tr></tbody></table><h3 id="a-3-licoes-dos-artigos-para-o-t4" tabindex="-1">A.3 Lições dos Artigos para o T4 <a class="header-anchor" href="#a-3-licoes-dos-artigos-para-o-t4" aria-label="Permalink to &quot;A.3 Lições dos Artigos para o T4&quot;">​</a></h3><ol><li><p><strong>Parcimônia primeiro:</strong> O teorema da aproximação universal (Funayama, 1997) sugere que uma única camada intermediária bem projetada é suficiente. No T4, isso significa que <code>expand</code> não deve ser usado indiscriminadamente — a arquitetura mínima que resolve o problema é a arquitetura correta.</p></li><li><p><strong>Múltiplos algoritmos, múltiplos resultados:</strong> Castro et al. (1999) mostraram que A*, CASCOR e PPL produzem arquiteturas diferentes para o mesmo problema. O T4 deve expor múltiplos operadores de descoberta (equivalentes a diferentes estratégias construtivas) para que o agente escolha a mais adequada ao domínio.</p></li><li><p><strong>Critério de parada ≈ Threshold de cristalização:</strong> O MSE=0.01 define quando o A* para de crescer. No T4, o equivalente é o limiar de confiança da Fractal Boundary — que determina quando uma entidade transita de Fluida para Cristalizada. <strong>Sem critério de parada, o grafo cresce indefinidamente.</strong></p></li><li><p><strong>&quot;Construtivo&quot; não significa &quot;sempre crescer&quot;:</strong> A* e CASCOR frequentemente não adicionaram neurônios — a arquitetura inicial já era suficiente. O T4 deve suportar a decisão de <strong>não expandir</strong>.</p></li><li><p><strong>PPL como inspiração para <code>project</code>:</strong> O PPL projeta dados em subespaço revelando estrutura latente. É análogo direto ao operador <code>project(entity, axes)</code> — mudar o eixo de observação para revelar relações que não são visíveis no eixo original.</p></li></ol><h3 id="a-4-referencias-dos-artigos-base" tabindex="-1">A.4 Referências dos Artigos Base <a class="header-anchor" href="#a-4-referencias-dos-artigos-base" aria-label="Permalink to &quot;A.4 Referências dos Artigos Base&quot;">​</a></h3><ul><li>Vargas, E. C., Sousa, H. C., Carvalho, A. C. P. L. F. (1998). &quot;Reconhecimento de Alvos utilizando Redes Neurais Construtivas.&quot; <em>IX SBSR</em>, INPE, 1247-1256.</li><li>Castro, L. N., Iyoda, E. M., Pinheiro, E., Von Zuben, F. (1999). &quot;Redes Neurais Construtivas: Uma Abordagem Comparativa.&quot; <em>IV Brazilian Conference on Neural Networks</em>, ITA, 102-107.</li><li>Fahlman, S. E., Lebiere, C. (1990). &quot;The Cascade-Correlation Learning Architecture.&quot; <em>NIPS 2</em>, 524-532.</li><li>Frean, M. (1990). &quot;The Upstart Algorithm.&quot; <em>Neural Computation</em>, 2(2), 198-209.</li><li>Reed, R. (1993). &quot;Pruning Algorithms — A Survey.&quot; <em>IEEE Trans. Neural Networks</em>, 4(5), 740-747.</li></ul>`,88)])])}const g=a(t,[["render",i]]);export{u as __pageData,g as default};
